import { useState, useEffect } from "react";
import axios from "axios";

const API = "http://127.0.0.1:5000";

export default function App() {
  const [email, setEmail] = useState("");
  const [apiKey, setApiKey] = useState("");
  const [usage, setUsage] = useState([]);
  const [filteredUsage, setFilteredUsage] = useState([]);
  const [response, setResponse] = useState("");
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState("");
  const [query, setQuery] = useState("");
  const [dark, setDark] = useState(true);
  const [endpoint, setEndpoint] = useState("todos");

  const theme = dark
    ? {
        bg: "#0f172a",
        card: "#1e293b",
        text: "#f1f5f9",
      }
    : {
        bg: "#f1f5f9",
        card: "#ffffff",
        text: "#020617",
      };

  useEffect(() => {
    setFilteredUsage(
      usage.filter((u) =>
        u.url.toLowerCase().includes(query.toLowerCase())
      )
    );
  }, [query, usage]);

  const signup = async () => {
    setLoading(true);
    const res = await axios.post(`${API}/auth/signup`, { email });
    setApiKey(res.data.apiKey);
    setLoading(false);
    setMessage("API Key generated");
  };

  const callAPI = async () => {
    setLoading(true);
    const res = await axios.get(
      `${API}/proxy?url=https://jsonplaceholder.typicode.com/${endpoint}/1&apiKey=${apiKey}`
    );
    setResponse(JSON.stringify(res.data, null, 2));
    setLoading(false);
  };

  const fetchUsage = async () => {
    const res = await axios.get(`${API}/usage/${apiKey}`);
    setUsage(res.data);
  };

  const exportLogs = () => {
    const blob = new Blob([JSON.stringify(usage)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = "usage.json";
    a.click();
  };

  const billing = (usage.length * 0.2).toFixed(2);

  return (
    <div style={{ background: theme.bg, minHeight: "100vh", color: theme.text, fontFamily: "Segoe UI" }}>

      {/* NAVBAR */}
      <div style={{ display: "flex", justifyContent: "space-between", padding: "15px 30px" }}>
        <h2>🚀 MeterFlow</h2>
        <button onClick={() => setDark(!dark)}>
          Toggle Theme
        </button>
      </div>

      <div style={{ padding: "30px" }}>

        <h1>Dashboard</h1>
        <p>{message}</p>

        {/* CARDS */}
        <div style={{ display: "flex", gap: "15px", marginBottom: "20px" }}>
          <Card title="Requests" value={usage.length} theme={theme} />
          <Card title="Billing ₹" value={billing} theme={theme} />
          <Card title="API Key" value={apiKey ? "Active" : "None"} theme={theme} />
        </div>

        {/* API KEY */}
        <div style={cardStyle(theme)}>
          <input value={email} onChange={(e) => setEmail(e.target.value)} placeholder="email" />
          <button onClick={signup}>{loading ? "..." : "Generate Key"}</button>
          {apiKey && <p>{apiKey}</p>}
        </div>

        {/* PLAYGROUND */}
        {apiKey && (
          <div style={cardStyle(theme)}>
            <select onChange={(e) => setEndpoint(e.target.value)}>
              <option value="todos">Todos</option>
              <option value="posts">Posts</option>
              <option value="users">Users</option>
            </select>

            <button onClick={callAPI}>Call API</button>
            <button onClick={fetchUsage}>Load Usage</button>
            <button onClick={exportLogs}>Export Logs</button>

            {response && <pre>{response}</pre>}
          </div>
        )}

        {/* SEARCH */}
        <input
          placeholder="Search logs..."
          value={query}
          onChange={(e) => setQuery(e.target.value)}
        />

        {/* TABLE */}
        <div style={cardStyle(theme)}>
          <table width="100%">
            <thead>
              <tr>
                <th>URL</th>
                <th>Status</th>
                <th>Time</th>
              </tr>
            </thead>
            <tbody>
              {filteredUsage.map((u, i) => (
                <tr key={i}>
                  <td>{u.url}</td>
                  <td>{u.status}</td>
                  <td>{new Date(u.timestamp).toLocaleString()}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* SIMPLE GRAPH */}
        <div style={cardStyle(theme)}>
          <h3>Usage Trend</h3>
          <canvas id="chart" height="100"></canvas>
        </div>

      </div>
    </div>
  );
}

function Card({ title, value, theme }) {
  return (
    <div style={{ ...cardStyle(theme), flex: 1 }}>
      <h4>{title}</h4>
      <h2>{value}</h2>
    </div>
  );
}

const cardStyle = (theme) => ({
  background: theme.card,
  padding: "20px",
  borderRadius: "10px",
  marginBottom: "20px",
});
